在Uniapp中，可以使用`uni.getImageInfo()` API获取图片信息，然后使用`uni.getFileSystemManager()` API读取图片文件的二进制数据，再使用`base64js`库将二进制数据转为base64字符串。使用方法如下：

1. 安装`base64js`库，可以使用npm或者直接下载库文件。

```
npm install base64-js
```

2. 在需要使用的页面或组件中引入`base64js`库，并获取图片文件的二进制数据。

```javascript
// 引入base64js库
import * as base64js from 'base64-js';

// 获取图片信息
uni.getImageInfo({
  src: '/static/demo.jpg',
  success: function (res) {
    let filePath = res.path;

    // 获取文件系统管理器
    let fs = uni.getFileSystemManager();

    // 读取图片文件的二进制数据
    fs.readFile({
      filePath: filePath,
      encoding: 'base64',
      success: function (res) {
        let imageBase64 = res.data;
        console.log(imageBase64);

        // 将base64字符串转为二进制数据
        let imageData = base64js.toByteArray(imageBase64);
        console.log(imageData);
      },
      fail: function (err) {
        console.log(err);
      }
    })
  }
})
```

在上面的代码中，我们首先使用`uni.getImageInfo()` API获取图片信息，然后使用获取到的`filePath`参数作为`uni.getFileSystemManager()` API的参数，获取文件系统管理器。接着，使用文件系统管理器的`readFile()`方法读取图片文件的二进制数据，并将其转为base64字符串和二进制数据。

